export const getGetAdminPredictionsUrl = (
  params: GetAdminPredictionsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/admin/predictions?${stringifiedParams}`
    : `/api/admin/predictions`;
};

export const getAdminPredictions = async (
  params: GetAdminPredictionsParams,
  options?: RequestInit,
): Promise<MatchPredictionSummary[]> => {
  return customFetch<MatchPredictionSummary[]>(
    getGetAdminPredictionsUrl(params),
    {
      ...options,
      method: "GET",
    },
  );
};

export const getGetAdminPredictionsQueryKey = (
  params?: GetAdminPredictionsParams,
) => {
  return [`/api/admin/predictions`, ...(params ? [params] : [])] as const;
};

export const getGetAdminPredictionsQueryOptions = <
  TData = Awaited<ReturnType<typeof getAdminPredictions>>,
  TError = ErrorType<unknown>,
>(
  params: GetAdminPredictionsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAdminPredictions>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetAdminPredictionsQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getAdminPredictions>>
  > = ({ signal }) =>
    getAdminPredictions(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getAdminPredictions>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetAdminPredictionsQueryResult = NonNullable<
  Awaited<ReturnType<typeof getAdminPredictions>>
>;
export type GetAdminPredictionsQueryError = ErrorType<unknown>;

export function useGetAdminPredictions<
  TData = Awaited<ReturnType<typeof getAdminPredictions>>,
  TError = ErrorType<unknown>,
>(
  params: GetAdminPredictionsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getAdminPredictions>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getGetAdminPredictionsQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}
